Here's a solid pattern using `MockHttpMessageHandler` and MSTest's async support:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Helper: mock handler to control HttpClient responses
    private static HttpClient CreateMockClient(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
    {
        return new HttpClient(new MockHandler(handler));
    }

    private class MockHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> handler)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken ct) => handler(request, ct);
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        using var client = CreateMockClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("hello")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_On404()
    {
        using var client = CreateMockClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.NotFound)));

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Cancellation: verify the token is respected
    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        using var client = CreateMockClient((_, ct) =>
        {
            ct.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage());
        });

        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<OperationCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Timeout: use CancellationTokenSource with a deadline
    [TestMethod]
    public async Task FetchAsync_Throws_WhenTimedOut()
    {
        using var client = CreateMockClient(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct); // simulate slow server
            return new HttpResponseMessage();
        });

        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // MSTest also supports [Timeout] at the test level (milliseconds)
    [TestMethod]
    [Timeout(2000)]
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        using var client = CreateMockClient((_, _) =>
            Task.FromResult(new HttpResponseMessage(System.Net.HttpStatusCode.OK)
            {
                Content = new StringContent("fast")
            }));

        var fetcher = new DataFetcher(client);
        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }
}
```

**Key patterns:**

| Technique | When to use |
|---|---|
| `CancellationTokenSource` + pre-cancel | Test that your code forwards the token |
| `CancellationTokenSource(TimeSpan)` | Simulate timeout from caller side |
| `[Timeout(ms)]` attribute | Guard against tests hanging indefinitely |
| `MockHttpMessageHandler` | Avoid real HTTP calls; control responses |

**Pitfalls to avoid:**
- Don't use `Task.Result` or `.Wait()` — this deadlocks in async tests. Always `await`.
- `TaskCanceledException` inherits from `OperationCanceledException`, so catch the more specific type when distinguishing timeout vs. explicit cancellation.
- Always `using` your `CancellationTokenSource` and `HttpClient` to avoid leaks.
